"use client";
import { useState, useEffect } from "react";

export default function TemplateDropdown({ onSelect }) {
  const [templates, setTemplates] = useState([]);
  const [selected, setSelected] = useState("");

  useEffect(() => {
    async function fetchTemplates() {
      const res = await fetch("http://localhost:8000/templates");
      const data = await res.json();
      setTemplates(data);
    }
    fetchTemplates();
  }, []);

  return (
    <div>
      <label className="center block text-sm font-medium text-gray-700 mb-2">
        Choose a Template
      </label>

      <select
        value={selected}
        onChange={(e) => {
          setSelected(e.target.value);
          onSelect(e.target.value);
        }}
        className="block rounded-md border-white-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm text-black"
      >
        <option value="">-- Select a Template --</option>
        {templates.map((tpl) => (
          <option key={tpl.template_id} value={tpl.template_id}>
            {tpl.name}
          </option>
        ))}
      </select>
    </div>
  );
}
